195:function addTitleEmojis(){var R=st.recipe;if(!R)return;var e=prompt('Add emojis:','');if(e&&e.trim()){R.recipeEmojis=(R.recipeEmojis||'')+e.trim();render();}}
551:function showDetail(id){var r=st.saved.find(function(s){return s._id===id;});if(r){st.recipe=r;st.view='detail';st.chk={};render();}}
612:var recipe={};recipe.title=raw.name||raw.title||'';recipe.author=typeof raw.author==='object'?raw.author.name:raw.author||'';recipe.description=raw.description||'';recipe.image=Array.isArray(raw.image)?raw.image[0]:(typeof raw.image==='object'?raw.image.url:raw.image)||'';recipe.servings=raw.recipeYield||'';recipe.prepTime=raw.prepTime||'';recipe.cookTime=raw.cookTime||'';recipe.totalTime=raw.totalTime||'';recipe.ingredients=(raw.recipeIngredient||raw.ingredients||[]).map(function(s){return toFraction(clean(s));});recipe.instructions=(raw.recipeInstructions||raw.instructions||[]).map(function(s){return typeof s==='object'?s.text:s;});recipe._id=Date.now().toString();recipe.recipePhoto=null;recipe._saved=isSaved(recipe._id);recipe.sourceUrl=u;stopBurst();st.recipe=recipe;st.view='detail';st.chk={};}else{st.view='error';st.errorMsg='Could not extract recipe from this URL. Try Serious Eats, AllRecipes, or NYT Cooking.';}render();}catch(e){st.view='error';st.errorMsg='Could not load this page. Try a different recipe URL.';render();}}).catch(function(e){stopBurst();st.view='error';st.errorMsg='Could not load this page. Try a different recipe URL.';render();});setTimeout(function(){if(st.view==='loading'){st.view='error';st.errorMsg='Request timed out. Try again or a different recipe URL.';render();}},90000);}function extractAndShow(html,u){var recipe=extractRecipe(html,u);if(!recipe||(!recipe.title&&!recipe.ingredients.length&&!recipe.instructions.length)){st.errorMsg='No recipe found on this page. Try a different URL.';st.view='error';}else{recipe._id=Date.now().toString();recipe._saved=isSaved(recipe._id);st.recipe=recipe;st.view='detail';st.chk={};}render();}
613:function render(){document.getElementById('bg').style.display='none';var app=document.getElementById('app');var V=st.view;var R=st.recipe;var sc=st.saved.length;var fl=st.sq?st.saved.filter(function(r){return(r.title||'').toLowerCase().indexOf(st.sq.toLowerCase())>=0||(r.ingredients||[]).some(function(i){return i.toLowerCase().indexOf(st.sq.toLowerCase())>=0;});}):st.saved;if(V==='loading'){document.getElementById('bg').style.display='block';app.innerHTML='<div class="lw"><div class="panel-container"><div class="lw2"><div class="sn"></div><p class="lt2">Extracting recipe...</p><p class="lu2">'+C(st.loadingUrl||'').replace('https://','').replace('http://','').split('/')[0]+'</p></div>';return;}if(V==='error'){app.innerHTML='<div class="tb" style="position:fixed;bottom:85px;left:16px;right:16px;z-index:99"><button class="ta ac">Rip</button><button class="ta" onclick="st.view=\'saved\';render()">Saved'+(sc>0?'<span class="ba">'+sc+'</span>':'')+'</button></div><div class="is"><div class="ir"><input class="ui" id="u2" type="url" placeholder="Paste Recipe Link Here" onkeydown="if(event.key===\'enter\')rip(this.value)" autofocus><button class="bt" onclick="rip(document.getElementById(\'u2\').value)">Rip It</button></div></div><div class="eb"><p>'+C(st.errorMsg||'Something went wrong')+'</p></div><div class="es"><div class="ei">&#x1F50D;</div><p class="et">No recipe found</p><p class="ed">Try Serious Eats, AllRecipes, NYT Cooking, Bon Appetit.</p></div>';return;}if(V==='detail'&&R){var ings=R.ingredients||[];var steps=R.instructions||[];var h='<button class="bk" onclick="st.view=\'home\';st.recipe=null;render()"> Back</button>'; h+='<div class="rb"><div class="rth"><h1 class="rt" onclick="var t=prompt(\'Rename recipe:\',\''+C(R.title).replace(/'/g,"\\'")+'\');if(t&&t.trim()){R.title=t.trim();render();}" style="cursor:pointer" title="Click to rename">'+C(R.title)+'</h1>';if(R.recipeEmojis)h+='<div class="re">'+C(R.recipeEmojis)+'</div>';h+='</div>';if(R.author)h+='<p class="ra">by '+C(R.author)+'</p>';h+='<div class="ph">';if(R.recipePhoto&&!R.recipePhoto.startsWith('data:image')){h+='<div class="ph-img" style="background:linear-gradient(135deg,#FFF0EB,#FFE4D6);border-radius:16px;height:200px;display:flex;align-items:center;justify-content:center;font-size:64px;cursor:pointer;overflow:hidden;text-align:center;line-height:200px" onclick="removePhoto()">'+R.recipePhoto+'</div>';}else if(R.recipePhoto){h+='<img src="'+R.recipePhoto+'" alt="recipe photo" style="width:100%;height:200px;object-fit:cover;border-radius:16px;cursor:pointer" onclick="removePhoto()">';}else{h+='<button class="ap" onclick="document.getElementById(\'phInput\').click()">+ Add Photo</button>';h+='<button class="ap2" onclick="addTitleEmojis()">+ Add Emojis</button>';}h+='<input type="file" id="phInput" accept="image/*" style="display:none" onchange="handlePhoto(this.files[0])">';h+='</div>';h+='<div class="rm">';h+='</div>';if(R.description)h+='<p class="ds">'+C(R.description)+'</p>';if(ings.length){h+='<p class="st">Ingredients ('+ings.length+')</p><ul class="il2">';for(var ii=0;ii<ings.length;ii++){var k=(R._id||'')+'-'+ii;var ch=!!st.chk[k];h+='<li id="ing-'+ii+'" class="'+(ch?'chk ':'')+'" onclick="toggleIng(\''+(R._id||'')+'\','+ii+')"><span class="ci">'+(ch?'\u2713':'\u25CB')+'</span>'+C(ings[ii])+'</li>';}h+='</ul>';}if(steps.length){h+='<p class="st">Instructions ('+steps.length+' steps)</p><ol class="is2">';for(var si=0;si<steps.length;si++){h+='<li><span class="sn2">'+(si+1)+'</span><span>'+C(steps[si])+'</span></li>';}h+='</ol>';}h+='</div><div class="ra2"><a class="ob" href="'+C(R.sourceUrl)+'" target="_blank" rel="noopener noreferrer">&#x2197; Open Original Recipe</a></div><div class="sb"><button class="sv '+(R._saved?'gd':'')+'" onclick="toggleSave()">'+(R._saved?'\u2713 Saved':'+ Save Recipe')+'</button></div>';app.innerHTML=h;return;}if(V==='saved'){var sh='<button class="bk" onclick="st.view=\'home\';render()"> Home</button>'; sh+='<div class="tb" style="position:fixed;bottom:85px;left:16px;right:16px;z-index:99"><button class="ta" onclick="st.view=\'home\';render()">Rip</button><button class="ta ac">Saved'+(sc>0?'<span class="ba">'+sc+'</span>':'')+'</button></div>';if(sc>0)sh+='<div class="sw"><span class="sic">&#x1F50D;</span><input class="si2" type="search" placeholder="Search recipes..." value="'+C(st.sq)+'" oninput="st.sq=this.value;render()"></div>';if(sc===0){sh+='<div style="height:120px"></div><div class="es"><div class="ei">&#x1F4D6;</div><p class="et">No saved recipes yet</p><p class="ed">Rip a recipe and tap "Save Recipe" to keep it here.</p></div>';}else if(fl.length===0){sh+='<div class="es"><div class="ei">&#x1F50D;</div><p class="et">No matches</p></div>';}else{sh+='<div class="sl">';for(var ri=0;ri<fl.length;ri++){var rv=fl[ri];sh+='<div class="sc" onclick="showDetail(\''+rv._id+'\')">';if(rv.image)sh+='<img class="sth" src="/api/proxy-image?url='+encodeURIComponent(rv.image)+'" alt="" onerror="this.style.display=\'none\'">';else sh+='<div class="stp">&#x1F37D;</div>';sh+='<div class="si"><p class="stt">'+C(rv.title)+'</p><div class="sm"><span>'+(rv.ingredients||[]).length+' ingredients</span><a href="'+C(rv.sourceUrl)+'" target="_blank" rel="noopener noreferrer">'+H(rv.sourceUrl)+'</a></div></div><div class="sac"><button class="mb dl" onclick="event.stopPropagation();delSaved(\''+rv._id+'\',event)" title="Delete">&#x1F5D1;</button></div></div>';}sh+='</div>';}app.innerHTML=sh;return;}var h='<div class="tb"><button class="ta ac">Rip</button><button class="ta" onclick="st.view=\'saved\';render()">Saved'+(sc>0?'<span class="ba">'+sc+'</span>':'')+'</button></div><div class="is"><div class="ir"><input class="ui" id="urlInput" type="url" placeholder="https://www.seriouseats.com/recipe..." onkeydown="if(event.key===\'enter\')rip(this.value)" autofocus><button class="bt" onclick="rip(document.getElementById(\'urlInput\').value)">Rip It</button></div></div>';if(sc>0){h+='<div style="margin-bottom:20px"><div class="rh2"><p class="rl">Recent Saves</p><button class="va" onclick="st.view=\'saved\';render()">View all &#x2192;</button></div><div class="sl">';for(var ri=0;ri<Math.min(3,sc);ri++){var rv=st.saved[ri];h+='<div class="sc" onclick="showDetail(\''+rv._id+'\')">';if(rv.image)h+='<img class="sth" src="/api/proxy-image?url='+encodeURIComponent(rv.image)+'" alt="" onerror="this.style.display=\'none\'">';else h+='<div class="stp">&#x1F37D;</div>';h+='<div class="si"><p class="stt">'+C(rv.title)+'</p><div class="sm"><span>'+(rv.ingredients||[]).length+' ingredients</span></div></div></div>';}h+='</div></div>';}h+='<div class="es"><div class="ei">&#x1F374;</div><p class="et">Stop reading. Start cooking.</p><p class="ed">Paste any recipe URL above to get just the recipe. No ads, no life story.</p></div>';app.innerHTML=h;}

